#include <bits/stdc++.h>
using namespace std;
const int maxn=1000010;
int a[maxn],n,m,q;
int find(int x,int l,int r){
    if(a[l]==x)return l;
    if(l>=r)return -1;
    int mid=l+((r-l)>>1);
    if(a[mid]>=x)return find(x,l,mid);
    else return find(x,mid+1,r);
}
int main(){
    cin>>n>>m;
    for(int i=1;i<=n;i++)cin>>a[i];
    for(int i=1;i<=m;i++){
        cin>>q;
        cout<<find(q,1,n)<<' ';
    }
    return 0;
}
